import { useState } from "react";
import { ChevronLeft, ChevronRight } from "lucide-react";
import { cn } from "../lib/utils";

export function Timeline({ items }) {
  const [active, setActive] = useState(0);

  const prev = () => setActive((i) => Math.max(0, i - 1));
  const next = () => setActive((i) => Math.min(items.length - 1, i + 1));

  return (
    <div className="w-full">
      <div className="hidden md:flex items-center gap-4 select-none">
        {items.map((item, idx) => (
          <button
            key={item.id}
            onClick={() => setActive(idx)}
            className={cn(
              "flex-1 group",
              idx !== items.length - 1 && "pr-4"
            )}
            aria-current={active === idx}
          >
            <div className="flex items-center gap-3">
              <div
                className={cn(
                  "size-8 shrink-0 rounded-full border grid place-items-center text-xs font-semibold",
                  active === idx
                    ? "border-transparent text-white bg-gradient-to-r from-[#072D42] via-[#F29E38] to-[#072D42] bg-[length:200%_200%] animate-gradient-x shadow-md"
                    : "border-border bg-white text-brand-dark/80"
                )}
              >
                {idx + 1}
              </div>
              <div className="flex-1">
                <p className={cn("text-sm", active === idx ? "text-brand-dark font-medium" : "text-brand-dark/70")}>
                  {item.label}
                </p>
                <div
                  className={cn(
                    "h-1 rounded-full mt-1",
                    active === idx
                      ? "bg-gradient-to-r from-[#072D42] via-[#F29E38] to-[#072D42] bg-[length:200%_200%] animate-gradient-x"
                      : "bg-beige-300/60 group-hover:bg-beige-300"
                  )}
                />
              </div>
            </div>
          </button>
        ))}
      </div>

      <div className="mt-6 rounded-xl p-[2px] bg-gradient-to-r from-[#072D42] via-[#F29E38] to-[#072D42] bg-[length:200%_200%] animate-gradient-x shadow-sm">
        <div className="bg-white rounded-xl p-6">
          <div className="flex items-center justify-between mb-4">
            <button
              onClick={prev}
              className="p-2 rounded-md border border-border hover:bg-beige-100 text-brand-dark"
              aria-label="Anterior"
            >
              <ChevronLeft className="size-5" />
            </button>
            <div className="text-center">
              <p className="text-xs uppercase tracking-wider text-brand-dark/60">
                {items[active].label}
              </p>
              <h4 className="font-serif text-2xl text-brand-dark mt-1">
                {items[active].title}
              </h4>
            </div>
            <button
              onClick={next}
              className="p-2 rounded-md border border-border hover:bg-beige-100 text-brand-dark"
              aria-label="Siguiente"
            >
              <ChevronRight className="size-5" />
            </button>
          </div>
          <p className="text-brand-dark/80 leading-relaxed">
            {items[active].description}
          </p>
        </div>
      </div>

      <div className="md:hidden mt-4 flex items-center justify-center gap-2 text-xs text-brand-dark/60">
        {items.map((_, i) => (
          <span
            key={i}
            className={cn(
              "h-1.5 w-6 rounded-full",
              i === active
                ? "bg-gradient-to-r from-[#072D42] via-[#F29E38] to-[#072D42]"
                : "bg-beige-300"
            )}
          />
        ))}
      </div>
    </div>
  );
}
